import UIKit
import Alamofire

// Define a custom enum for Stock
enum Stock {
    case AAPL
    case GOOG
}

class TradeManager {
    
    // Manage user's portfolio
    var portfolio: [String: Double] = [:]
    
    // Function to execute trades
    func executeTrade(stock: String, amount: Int, action: "BUY" | "SELL") {
        
        // Check if stock is valid
        guard let stockValue = Stock(rawValue: stock) else { return }
        
        switch stockValue {
        case .AAPL:
            print("Executing trade for AAPL")
        case .GOOG:
            print("Executing trade for GOOG")
        default:
            return
        }
        
        // Simulate API call to execute trade
        AF.request("https://api.example.com/trade", method: .post, parameters: ["stock": stock, "amount": amount, "action": action])
            .responseString { response in
                switch response.result {
                case .success(let value):
                    print("Trade executed successfully")
                case .failure(let error):
                    print(error)
                }
        }
    }
    
}

class PortfolioManager {
    
    // Function to add stocks to portfolio
    func addToPortfolio(stock: String, amount: Double) {
        
        // Update portfolio dictionary
        if var value = portfolio[stock] {
            value += amount
            portfolio[stock] = value
        } else {
            portfolio[stock] = amount
        }
        
        print("Added \(amount) units of \(stock) to portfolio")
    }
    
    // Function to remove stocks from portfolio
    func removeFromPortfolio(stock: String, amount: Double) {
        
        // Update portfolio dictionary
        if var value = portfolio[stock] {
            if value > amount {
                value -= amount
                portfolio[stock] = value
            } else {
                print("Not enough units of \(stock) to remove")
            }
        } else {
            print("No units of \(stock) in portfolio")
        }
        
    }
    
}

class TradingViewController: UIViewController {
    
    // Create instance variables for trade manager and portfolio manager
    let tradeManager = TradeManager()
    let portfolioManager = PortfolioManager()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        // Initialize portfolio manager
        if portfolio.isEmpty {
            addToPortfolio(stock: "AAPL", amount: 100.0)
            addToPortfolio(stock: "GOOG", amount: 200.0)
        }
        
    }
    
    // Function to add stock to portfolio when user taps on button
    @IBAction func addButtonTapped(_ sender: UIButton) {
        
        let stock = sender.tag
        let amount = Double(inputField.text ?? "") ?? 0.0
        
        addToPortfolio(stock: String(stock), amount: amount)
    }
    
}